mapper.sql:
WHERE COALESCE(USE_AT, 'Y') = 'Y'

    AND DELIVERY_MODE = #{deliveryChannel}


    AND DELIVERY_STATUS = #{deliveryStatus}


    AND (
        UPPER(COALESCE(TOP_FINDING, '')) LIKE '%' || UPPER(#{deliveryKeyword}) || '%'
        OR UPPER(COALESCE(DELIVERY_DETAIL, '')) LIKE '%' || UPPER(#{deliveryKeyword}) || '%'
        OR UPPER(COALESCE(ACTOR_USER_ID, '')) LIKE '%' || UPPER(#{deliveryKeyword}) || '%'
        OR UPPER(COALESCE(DELIVERY_MODE, '')) LIKE '%' || UPPER(#{deliveryKeyword}) || '%'
    )

WHERE COALESCE(USE_AT, 'Y') = 'Y'
AND ACTION_CODE = #{activityAction}
AND ( UPPER(COALESCE(TARGET_TEXT, '')) LIKE '%' || UPPER(#{activityKeyword}) || '%' OR UPPER(COALESCE(DETAIL_TEXT, '')) LIKE '%' || UPPER(#{activityKeyword}) || '%' OR UPPER(COALESCE(ACTOR_USER_ID, '')) LIKE '%' || UPPER(#{activityKeyword}) || '%' OR UPPER(COALESCE(ACTION_CODE, '')) LIKE '%' || UPPER(#{activityKeyword}) || '%' )
